import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Lq6hU67C.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Addressables Leak Detector","text":"","tagline":"Find forgotten Addressables.Release calls — live handle list with file:line origins and zero manual instrumentation.","actions":[{"theme":"brand","text":"Quick Start","link":"/guide/quick-start"},{"theme":"alt","text":"Core concepts","link":"/concepts/layers-and-event-log"}]},"features":[{"title":"IL Post-Processor","details":"Injects HandleTracker at Load and Release call sites after compilation — file:line by default, optional stack traces in Verbose mode."},{"title":"Live Leaks tab","details":"Passive list of live handles grouped by call site and asset, with severity heuristics and leak trace detail."},{"title":"Scene-survivor detection","details":"Flags handles that survive non-additive scene changes without Release — high-confidence leak signal."},{"title":"Allowlist & attributes","details":"Suppress noise for startup preloads via [AddressablesIntentionallyPersistent] or Editor pattern ignore."},{"title":"Public API only","details":"Handle identity via GetHashCode, Equals, IsValid, DebugName — no reflection on private Addressables fields."},{"title":"Demo scene","details":"One-click demo with manual and ILPP-instrumented leak scenarios for Play Mode validation."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function l(n,e,r,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s('<h2 id="what-is-addressables-leak-detector" tabindex="-1">What is Addressables Leak Detector? <a class="header-anchor" href="#what-is-addressables-leak-detector" aria-label="Permalink to &quot;What is Addressables Leak Detector?&quot;">​</a></h2><p>Addressables Leak Detector is a <strong>Unity Editor</strong> tool for teams using <strong>Addressables</strong> who need to know <strong>which handle was loaded where and never released</strong> — silent ref-count leaks that do not show up clearly in the standard Memory Profiler.</p><div class="info custom-block"><p class="custom-block-title">Version note</p><p>Tested on Unity 6 LTS (<code>6000.3.7f1</code>) with Addressables <code>2.2.2</code>. See the compatibility table in <a href="./guide/installation.html">Installation</a>.</p></div><ul><li>Who loaded this asset, and from which script line?</li><li>Did this handle survive a scene change without Release?</li><li>Are we loading the same address twice while a prior handle is still live?</li></ul><h2 id="who-is-it-for" tabindex="-1">Who is it for? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who is it for?&quot;">​</a></h2><p>Projects using Addressables for content streaming where debugging missing <code>Release()</code> calls otherwise means guesswork, Memory Profiler diffing, or ad-hoc logging.</p><h2 id="what-it-is-not" tabindex="-1">What it is not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What it is not&quot;">​</a></h2><ul><li>Not a replacement for Memory Profiler (shows <strong>call-site origin</strong>, not full retention graph).</li><li>Not runtime analytics — Editor Play Mode focused.</li><li>Not an auto-alarm system — passive Live Leaks list with optional severity coloring.</li></ul><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h2><ul><li><strong>Health Graph</strong> (1.1) — ref-count sawtooth visualization.</li><li><strong>Snapshot Diff</strong> (1.2) — baseline / compare snapshots.</li></ul><p>Current release: <strong>Live Leaks</strong> tab only.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Follow the <a href="./guide/quick-start.html">Quick Start</a> to open the window and see your first live handle.</li><li>See <a href="./guide/installation.html">Installation</a> for Unity version and package requirements.</li><li>Browse <a href="./how-to/demo-scene.html">How-to guides</a> for demo scene, allowlist, ILPP diagnostics, and scene survival.</li></ul>',13)])])}const p=t(o,[["render",l]]);export{m as __pageData,p as default};
